mapper.select:
WITH 
SELECT 
FROM ASSIGNMENT A
JOIN STUDENT_CLASS SC ON SC.CLASS_ID = A.CLASS_ID
                    AND SC.STUDENT_ID = #{studentId}
                    AND SC.END_DATE IS NULL
LEFT JOIN LATEST_SUB SUB ON SUB.ASSIGN_ID = A.ASSIGN_ID
                        AND SUB.STUDENT_ID = #{studentId}
LEFT JOIN LATEST_ATTACH ATC ON ATC.PNO = SUB.SUB_ID
LEFT JOIN LATEST_FDB FDB ON FDB.SUB_ID = SUB.SUB_ID
WHERE A.CLASS_ID = #{classId}
  AND A.ASSIGN_ID = #{assignmentId}
  AND NVL(A.DELETE_YN, 0) = 0

mapper.insert:
INSERT INTO ASSIGN_SUB (
    SUB_ID, ASSIGN_ID, STUDENT_ID, CONTENT, SUBMIT_STATUS, SUBMIT_AT,
    LAST_SAVED_AT, RETURN_REASON, SCORE, CREATED_AT, UPDATED_AT, SUBMIT_COUNT
) VALUES (
    #{subId}, #{assignmentId}, #{studentId}, #{content, jdbcType=CLOB}, #{submitStatus}, SYSDATE,
    SYSDATE, NULL, 0, SYSDATE, SYSDATE, #{submitCount}
)

mapper.update:
UPDATE ASSIGN_SUB
   SET CONTENT = #{content, jdbcType=CLOB},
       SUBMIT_STATUS = #{submitStatus},
       SUBMIT_AT = SYSDATE,
       LAST_SAVED_AT = SYSDATE,
       RETURN_REASON = NULL,
       UPDATED_AT = SYSDATE,
       SUBMIT_COUNT = #{submitCount}
 WHERE SUB_ID = #{subId}
   AND ASSIGN_ID = #{assignmentId}
   AND STUDENT_ID = #{studentId}

